import React from "react";

export default function Pagination({ page, setPage, filteredLength, pageSize }) {
  if (filteredLength <= pageSize) return null;

  return (
    <div style={{
      textAlign: "center",
      display: "flex",
      justifyContent: "center",
      gap: "12px",
      margin: "10px 0",
    }}>
      <button onClick={() => setPage(p => p - 1)} disabled={page === 1}>←</button>
      <span>{page} / {Math.ceil(filteredLength / pageSize)}</span>
      <button onClick={() => setPage(p => p + 1)} disabled={page * pageSize >= filteredLength}>→</button>
    </div>
  );
}
